diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 73ba0f78e805..2bc386360f5d 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3479,6 +3479,32 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
     }
   }

+  // select !(signbit(X)), (X < 0), false --> false
+  // where signbit(X) is (trunc (lshr/ashr X, N)) and (X < 0) is icmp slt X, 0.
+  // These two expressions are equivalent, so select !A, A, false = false.
+  Value *XorOp0;
+  if (match(FalseVal, m_Zero()) &&
+      match(CondVal, m_c_Xor(m_Value(XorOp0), m_One()))) {
+    // Condition is (xor X, true) = !X
+    // Check if XorOp0 is trunc(shift(V, N)) and TrueVal is icmp slt V, 0
+    Value *ShOp, *V;
+    const APInt *ShAmt;
+    // Try lshr first
+    if (match(XorOp0, m_Trunc(m_LShr(m_Value(ShOp), m_APInt(ShAmt)))) &&
+        match(TrueVal, m_SpecificICmp(ICmpInst::ICMP_SLT, m_Value(V), m_Zero())) &&
+        ShOp == V) {
+      // Both are sign-bit tests of the same value: select !signbit(V), signbit(V), false
+      return replaceInstUsesWith(SI, Zero);
+    }
+    // Try ashr
+    if (match(XorOp0, m_Trunc(m_AShr(m_Value(ShOp), m_APInt(ShAmt)))) &&
+        match(TrueVal, m_SpecificICmp(ICmpInst::ICMP_SLT, m_Value(V), m_Zero())) &&
+        ShOp == V) {
+      // Both are sign-bit tests of the same value: select !signbit(V), signbit(V), false
+      return replaceInstUsesWith(SI, Zero);
+    }
+  }
+
   return nullptr;
 }

